// src/Index.jsx
import React from "react";
import Navbar from "./Navbar"; // 👈 Importamos tu Navbar

const Index = () => {
  return (
    <>
      {/* Navbar personalizado */}
      <Navbar />

      {/* Espaciado para que el contenido no quede debajo del Navbar */}
      <div style={{ height: "80px" }}></div>

      {/* Contenido principal */}
      <div
        style={{
          minHeight: "calc(100vh - 80px)",
          display: "flex",
          flexDirection: "column",
          justifyContent: "center",
          alignItems: "center",
          background: "linear-gradient(to right, #e0cbf5, #d6e6f2)",
          textAlign: "center",
          padding: "40px",
        }}
      >
        <h1 style={{ fontSize: "3rem", fontWeight: "bold", marginBottom: "20px" }}>
          Bienvenido a Synapse
        </h1>
        <p style={{ fontSize: "1.2rem", maxWidth: "600px", marginBottom: "30px" }}>
          Esta es la página principal de tu aplicación. Desde aquí puedes navegar
          hacia las diferentes secciones como <strong>Misión</strong>,{" "}
          <strong>Registro</strong> y <strong>Login</strong>.
        </p>
        <button
          style={{
            padding: "12px 25px",
            fontSize: "1rem",
            fontWeight: "600",
            borderRadius: "30px",
            border: "none",
            background: "#9370db",
            color: "white",
            cursor: "pointer",
            boxShadow: "0 4px 6px rgba(0,0,0,0.2)",
            transition: "0.3s ease",
          }}
          onMouseOver={(e) => (e.target.style.background = "#7a5ccf")}
          onMouseOut={(e) => (e.target.style.background = "#9370db")}
        >
          Comenzar
        </button>
      </div>
    </>
  );
};

export default Index;
